var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"이렇게 통신으로나마 만나 뵙게 되어 영광입니다, 사장님.","JPN":"通信上ではありますがお会いできて光栄です、社長。","ENG":"I'm honored to finally talk to you, although I'd much prefer it if it were offline.","TWN":"即使是以通信的方式，我還是非常榮幸能見到您，老闆。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"태스크포스 업계의 떠오르는 샛별, 코핀 컴퍼니의 명성에 대해선 익히 들어온 바......","JPN":"タスクフォース業界の期待の新星、コフィンカンパニーの名声についてはよく耳にしておりまして……","ENG":"I've heard great things about Coffin Company, the rising star in the TASKFORCE business.","TWN":"科芬公司身為特遣勢力業界新星，我對貴公司的名望早有耳聞……"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"이렇게 저희 두 강소기업이 만나 첫 교류의 장을 열게 된 순간을 기념하기 위해 약소한 선물을 보내드렸는데, 마음에 드셨을지 모르겠군요.","JPN":"こうして私どもと初交流の場を設けていただいたことの感謝に、ささやかながらプレゼントをお贈りしましたが、お気に召したでしょうか。","ENG":"I sent you a little gift to mark this amazing occasion where the two small giants in the business finally come to the same table. I hope you liked it.","TWN":"我們兩家強大的小公司今天是第一次見面交流，為紀念這一瞬間，我為您送上了一份小小的禮物，不知道您是否喜歡。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 감격에 겨운 나머지 소개를 잊었네요.","JPN":"おっと、感激のあまり自己紹介を忘れてしまいました。","ENG":"Oh, how rude of me. I was so thrilled that I forgot to introduce myself.","TWN":"啊，我太激動了，都忘了介紹呢。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"저는 군수기업 아이언 테일러의 신소재개발부 부장 피터 버렌이라고 합니다.","JPN":"私は軍需企業アイアンテイラーの新素材開発部長、ピーター・バーレンと申します。","ENG":"My name is Peter Burren, director of the Department of Advanced Materials Development, Iron Tailors.","TWN":"我是軍工企業鋼鐵泰勒的新材料開發部部長彼得·弗倫。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"또한 동시에, 아이언 테일러 주식의 20%를 보유하고 있는 임원이기도 하죠.","JPN":"部長と兼任して、アイアンテイラーの株式の20％を保有している役員でもあります。","ENG":"I'm also one of the executives of the company, currently holding 20% of the company's shares.","TWN":"同時，我也是鋼鐵泰勒20%股份的持有者。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 잘난 척이 아닙니다. 그만큼 제가 저희 회사의 비전을 높이 사고 있다고 생각해주시면 좋겠군요.","JPN":"ああ、決して自慢などではありません。ただ、私自身が弊社のビジョンを高く評価していると思っていただければと。","ENG":"Ah, I'm not trying to tell you I'm rich. I just wanted you to know how bright of a future I think this company has in front of it.","TWN":"啊，我並不是在臭屁。我只是希望您知道，我對我們公司有很高的展望。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"한때는 보잘것없는 의류공장으로 시작했지만, 지금은 이렇게 도시관리국의 인정을 받는 방위산업체로 성장했으니 말입니다.","JPN":"最初は一介の衣類工場でしたが、今ではこうして都市管理局認定の防衛産業企業に成長したものですから。","ENG":"After all, we started as a trivial clothes factory and grew to become a munitions company now acknowledged by the City Management.","TWN":"雖然最初只是個微不足道的服裝廠，但是現在我們已經成長為一家軍工企業，並得到了城市管理局的認可。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"당분간 자본확장을 위해 적극적으로 증자를 할 계획이니 사장님께도 저희 주식을 많이 매입해두길 권유 드리고 싶네요.","JPN":"当分の間、資本拡張のために積極的に増資をする計画ですので、社長も弊社の株式を買い取っておくことをおすすめします。","ENG":"We're planning an aggressive capital increase and expansion for the time being, so I'd suggest you to start buying our shares.","TWN":"目前我們為了擴大資本，正準備積極增大投資，因此我想向老闆提議多買進我們的股票。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"아이언 테일러의 주가그래프는 이제 곧 하늘 무서운 줄 모르고 치솟을 테니까요.","JPN":"アイアンテイラーの株価はもうじき右肩上がりになるでしょう。","ENG":"The stock price of Iron Tailors will hit the ceiling, I guarantee you.","TWN":"畢竟鋼鐵泰勒的股價將一路飆升突破天際。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 이런...... 흥분해서 얘기가 딴 길로 새버렸군요.","JPN":"おっと……つい夢中になって話が逸れてしまいましたね。","ENG":"Oh, look at me. I'm straying from the topic again.","TWN":"啊，這……我太興奮了，都說到其他事上去了。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"저희가 드리려는 의뢰는 간단합니다.","JPN":"お願いしたい依頼内容はとても簡単です。","ENG":"So, our request is simple.","TWN":"我們的委託十分簡單。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"이번에 저희가 신형 방호복을 기획했는데, 거기에 들어갈 신소재가...... 조금 독특하거든요.","JPN":"このたび弊社で新型防護服を企画しましたが、そこに必要な新素材が……少し独特なものでして。","ENG":"We've designed a brand new protective suit, and the material we need for its production is rather... unconventional, if I may.","TWN":"這次我們設計了一款新型防護服，其中需要用到的新素材……有些獨特。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"메일로 전송해드린 다이브 좌표에 저희가 찾고 있는 신소재들이 <color=#ffd34c>돌아다니고</color> 있을 겁니다.","JPN":"メールで転送したダイブ座標に弊社が探している新素材が<color=#ffd34c>動き回って</color>いると思います。","ENG":"These materials will be <color=#ffd34c>roaming around</color> at the dive coordinates I sent you via mail.","TWN":"我用郵件傳給您的躍入座標，就有我們在尋找的新素材<color=#ffd34c>轉悠</color>。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"타깃을 수거해주시되, 가급적 품질이 훼손되지 않도록 각별히 조심해주시길.","JPN":"ターゲットの収集をしていただきたいのですが、なるべく品質が落ちないように、くれぐれもご注意ください。","ENG":"I'd like you to collect the materials. And please, be extra careful not to damage it.","TWN":"回收目標時，請盡可能小心，不要對它的品質造成損傷。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};